                    initialState: true,
                    retryOnFailure: false,
                    switch: 'buttonbar', // 'menu' || 'buttonbar' || 'none'
                },
                startOffset: defaults.urlParams['t'] ? defaults.urlParams['t'] : 0,
                hotspots: {
