                mainRoll: {
                    adaptive: {
                        prebufferGoal: 40,
                    },
                    actionTags: flashvars.actionTags,
                    mediaPriority: flashvars.mediaPriority,
                    mediaDefinition: flashvars.mediaDefinitions,
